import React, { useEffect, useState } from 'react';
import Card from '../components/Card';
import { Chart as C, LineElement, BarElement, CategoryScale, LinearScale, PointElement, Tooltip, Legend, ArcElement } from 'chart.js';
import { Line, Bar, Doughnut } from 'react-chartjs-2';
import api from '../services/api';

C.register(LineElement, BarElement, CategoryScale, LinearScale, PointElement, Tooltip, Legend, ArcElement);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      setRefreshing(true);
      const res = await api.get('/admin/dashboard-stats');
      // Handle wrapped response
      setStats(res.data?.data || res.data);
    } catch (err) {
      console.error("Error fetching stats:", err);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  if (loading) return (
    <div className="loading-container">
      <div className="loading-spinner"></div>
      <div style={{ color: 'var(--text-secondary)', marginTop: '1rem' }}>Loading Dashboard...</div>
    </div>
  );

  if (!stats) return (
    <div className="error-container">
      <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>⚠️</div>
      <div style={{ color: 'var(--text-primary)', fontSize: '1.25rem' }}>Error loading data</div>
      <button onClick={fetchStats} className="btn btn-primary" style={{ marginTop: '1rem' }}>Retry</button>
    </div>
  );

  const { counts, charts, recentActivity } = stats;

  const filteredActivity = (recentActivity || []).filter(log => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (log.action || '').toLowerCase().includes(q) || (log.performedBy?.fullName || '').toLowerCase().includes(q);
  });

  const savingsData = {
    labels: charts.savings.map(d => d._id),
    datasets: [{
      label: 'Savings Growth ($)',
      data: charts.savings.map(d => d.total),
      borderColor: '#10b981',
      backgroundColor: 'rgba(16, 185, 129, 0.1)',
      tension: 0.4,
      fill: true,
      borderWidth: 3,
      pointBackgroundColor: '#10b981',
      pointBorderColor: '#ffffff',
      pointBorderWidth: 2,
      pointRadius: 5,
      pointHoverRadius: 7,
    }]
  };

  const loanData = {
    labels: charts.loans.map(d => d._id),
    datasets: [{
      label: 'Loan Status',
      data: charts.loans.map(d => d.count),
      backgroundColor: [
        'rgba(99, 102, 241, 0.8)',
        'rgba(244, 63, 94, 0.8)',
        'rgba(245, 158, 11, 0.8)',
        'rgba(16, 185, 129, 0.8)',
      ],
      borderColor: [
        '#6366f1',
        '#f43f5e',
        '#f59e0b',
        '#10b981',
      ],
      borderWidth: 2,
    }]
  };

  const chartOptions = {
    maintainAspectRatio: false,
    responsive: true,
    plugins: {
      legend: {
        labels: {
          color: '#b8c1ec',
          font: {
            size: 12,
            family: 'Inter'
          }
        }
      },
      tooltip: {
        backgroundColor: 'rgba(17, 25, 54, 0.95)',
        titleColor: '#ffffff',
        bodyColor: '#b8c1ec',
        borderColor: 'rgba(99, 102, 241, 0.3)',
        borderWidth: 1,
        padding: 12,
        cornerRadius: 8,
      }
    },
    scales: {
      y: {
        grid: {
          color: 'rgba(99, 102, 241, 0.1)',
        },
        ticks: {
          color: '#b8c1ec'
        }
      },
      x: {
        grid: {
          color: 'rgba(99, 102, 241, 0.1)',
        },
        ticks: {
          color: '#b8c1ec'
        }
      }
    }
  };

  return (
    <div className="fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div>
          <h2 className="page-title" style={{ marginBottom: '0.5rem' }}>📊 Dashboard Overview</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', margin: 0 }}>
            Real-time insights and analytics
          </p>
        </div>
        <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
          <div className="search-container" style={{ maxWidth: 320 }}>
            <svg className="search-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor">
              <circle cx="11" cy="11" r="8" />
              <path d="m21 21-4.35-4.35" />
            </svg>
            <input
              type="text"
              placeholder="Search recent activity..."
              className="search-input"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <button
            onClick={fetchStats}
            className={`btn btn-primary ${refreshing ? 'loading' : ''}`}
            disabled={refreshing}
            style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" className={refreshing ? 'rotating' : ''}>
              <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2" />
            </svg>
            {refreshing ? 'Refreshing...' : 'Refresh'}
          </button>
        </div>
      </div>

      <div className="card-row" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
        <Card
          title="Total Members"
          value={counts.members}
          icon="👥"
          color="#6366f1"
          gradient="linear-gradient(135deg, #667eea 0%, #764ba2 100%)"
        />
        <Card
          title="Total Staff"
          value={counts.staff}
          icon="🛡️"
          color="#8b5cf6"
          gradient="linear-gradient(135deg, #a78bfa 0%, #8b5cf6 100%)"
        />
        <Card
          title="Total Savings"
          value={`$${counts.savings.toLocaleString()}`}
          icon="💰"
          color="#10b981"
          gradient="linear-gradient(135deg, #34d399 0%, #10b981 100%)"
        />
        <Card
          title="Total Loans"
          value={`$${counts.loans.toLocaleString()}`}
          icon="💸"
          color="#f43f5e"
          gradient="linear-gradient(135deg, #fb7185 0%, #f43f5e 100%)"
        />
        <Card
          title="Pending Requests"
          value={counts.pending}
          icon="⏳"
          color="#f59e0b"
          gradient="linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%)"
        />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '2rem' }}>
        <div className="card" style={{ padding: '1.5rem' }}>
          <h4 style={{ margin: '0 0 1.5rem 0', color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 600 }}>
            💹 Savings Growth Trend
          </h4>
          <div style={{ height: '300px' }}>
            <Line data={savingsData} options={chartOptions} />
          </div>
        </div>
        <div className="card" style={{ padding: '1.5rem' }}>
          <h4 style={{ margin: '0 0 1.5rem 0', color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 600 }}>
            📊 Loan Distribution
          </h4>
          <div style={{ height: '300px' }}>
            <Bar data={loanData} options={chartOptions} />
          </div>
        </div>
      </div>

      <div className="card" style={{ padding: '1.5rem' }}>
        <h4 style={{ margin: '0 0 1.5rem 0', color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 600 }}>
          🕐 Recent Activity
        </h4>
        {filteredActivity.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)' }}>
            {searchQuery ? 'No activity matches your search.' : 'No recent activity.'}
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            {filteredActivity.map((log, idx) => (
              <div
                key={idx}
                className="activity-item"
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  padding: '1rem',
                  background: 'var(--bg-hover)',
                  borderRadius: '0.75rem',
                  border: '1px solid var(--border)',
                  transition: 'all 0.3s ease'
                }}
              >
                <div style={{
                  width: '10px',
                  height: '10px',
                  borderRadius: '50%',
                  background: 'var(--primary)',
                  marginRight: '1rem',
                  boxShadow: '0 0 10px rgba(99, 102, 241, 0.5)'
                }}></div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: '500', color: 'var(--text-primary)', marginBottom: '0.25rem' }}>
                    {log.action}
                  </div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>
                    by {log.performedBy?.fullName || 'Unknown'} • {new Date(log.timestamp).toLocaleString()}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
export default Dashboard;
